import React, { useState, useEffect } from 'react';

function SentimentGauge() {
    const [sentimentData, setSentimentData] = useState({
        overall: 0.2, // -1 to 1
        positive: 45,
        neutral: 35,
        negative: 20,
        fearGreed: 32,
        activity: 'moderate',
        technical: 'strong',
        volatility: 'high'
    });

    // 移除自動更新定時器，改為靜態展示
    // 如果需要更新數據，可以通過props傳入或手動觸發

    const getSentimentLabel = (score) => {
        if (score > 0.3) return { label: '樂觀', color: '#10b981' };
        if (score > 0.1) return { label: '偏樂觀', color: '#34d399' };
        if (score > -0.1) return { label: '中性', color: '#f59e0b' };
        if (score > -0.3) return { label: '偏悲觀', color: '#fb7185' };
        return { label: '悲觀', color: '#ef4444' };
    };

    const sentiment = getSentimentLabel(sentimentData.overall);

    // 計算儀表盤角度 (-90度到90度)
    const gaugeAngle = sentimentData.overall * 90;

    return (
        <div className="sentiment-gauge-container">
            <div className="sentiment-gauge">
                <div className="gauge-container">
                    <div
                        className="gauge-fill"
                        style={{
                            transform: `rotate(${gaugeAngle}deg)`,
                            background: `conic-gradient(from 180deg, #ef4444 0deg, #f59e0b 90deg, #10b981 180deg)`
                        }}
                    ></div>
                    <div className="gauge-needle" style={{ transform: `rotate(${gaugeAngle}deg)` }}></div>
                    <div className="gauge-center">
                        <span className="gauge-value" style={{ color: sentiment.color }}>
                            {sentimentData.overall.toFixed(2)}
                        </span>
                        <span className="gauge-label" style={{ color: sentiment.color }}>
                            {sentiment.label}
                        </span>
                    </div>
                </div>
            </div>

            <div className="sentiment-breakdown">
                <div className="breakdown-item">
                    <span className="breakdown-emoji">😊</span>
                    <span>正面情緒</span>
                    <span className="breakdown-value positive">
                        {sentimentData.positive.toFixed(1)}%
                    </span>
                </div>
                <div className="breakdown-item">
                    <span className="breakdown-emoji">😐</span>
                    <span>中性情緒</span>
                    <span className="breakdown-value neutral">
                        {sentimentData.neutral.toFixed(1)}%
                    </span>
                </div>
                <div className="breakdown-item">
                    <span className="breakdown-emoji">😟</span>
                    <span>負面情緒</span>
                    <span className="breakdown-value negative">
                        {sentimentData.negative.toFixed(1)}%
                    </span>
                </div>
            </div>
        </div>
    );
}

export default SentimentGauge;
